#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
inline void pt(const int &p,const char &c='\n'){print(p<0?putchar('-'),-p:p);putchar(c);}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline void Swap(T&x,T&y){T tmp=x;x=y;y=tmp;}
const int N=2e6+10,MM=2e6+10,INF=0x3f3f3f3f,P=1<<17;int n,m;
struct Edge{int u,v,A,B;inline bool operator<(const Edge &Q)const{return A<Q.A;}}G[MM];
int fa[N],ch[N][2],mx[N],vl[N];bool tg[N];
//inline void debug(const int &x){printf("%d >> %d %d %d %d %d\n",x,fa[x],ch[x][0],ch[x][1],mx[x],vl[x]);}
inline bool nrt(int x){return ch[fa[x]][0]==x||ch[fa[x]][1]==x;}
inline void rev(int x){Swap(ch[x][0],ch[x][1]);tg[x]^=1;}
inline void pushdown(int x){if(tg[x])tg[x]=false,rev(ch[x][0]),rev(ch[x][1]);}
inline void update(int x)
{
	mx[x]=x;if(G[mx[x]].B<G[mx[ch[x][0]]].B)mx[x]=mx[ch[x][0]];
	if(G[mx[x]].B<G[mx[ch[x][1]]].B)mx[x]=mx[ch[x][1]];
}


inline void rotate(int x)
{
	int y=fa[x],z=fa[y];const bool &k=ch[y][1]==x;
	if(nrt(y))ch[z][ch[z][1]==y]=x;int w=ch[x][!k];ch[ch[x][!k]=y][k]=w;
	if(w)fa[w]=y;fa[fa[y]=x]=z;update(y);
}
inline void pushall(int x){nrt(x)?pushall(fa[x]):void();pushdown(x);}
//inline void wa(){debug(1);debug(2);debug(P|2);debug(P|3);debug(P|4);}
inline void splay(int x)
{
	pushall(x);int y=fa[x];
	while(nrt(x)){if(nrt(y=fa[x]))rotate((ch[fa[y]][0]==y)^(ch[y][0]==x)?x:y);rotate(x);}update(x);
}
inline void access(int x){for(int y=0;x;x=fa[y=x])splay(x),ch[x][1]=y,update(x);}
inline void makeRt(int x){access(x);splay(x);rev(x);}
inline int fndRt(int x){access(x);splay(x);while(ch[x][0])pushdown(x),x=ch[x][0];return x;}
inline void lnk(int x){makeRt(G[x].v);fa[fa[G[x].v]=x]=G[x].u;}
inline void cut(int x){access(G[x].v);splay(x);ch[x][0]=ch[x][1]=fa[ch[x][0]]=fa[ch[x][1]]=0;update(x);}
int main()
{
	n=read();m=read();rep(1,m,i)G[i].u=read()|P,G[i].v=read()|P,G[i].A=read(),G[i].B=read();std::sort(G+1,G+m+1);
	int ans=INF;rep(1,m,i)if(G[i].u!=G[i].v)
	{
		int y=G[i].u,z=G[i].v;makeRt(y);if(y!=fndRt(z))lnk(i);
		else if(G[i].B<G[mx[z]].B)cut(mx[z]),lnk(i);makeRt(P|1);
		if((P|1)==fndRt(P|n))ans=min(ans,G[i].A+G[mx[n|P]].B);
//		printf("%d\n",i);
	}
	pt(ans==INF?-1:ans);return 0;
}
